	"bytes"
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"errors"
	"fmt"
	"io"
	"mime"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	TimeoutExitCode = 124
	MaxBodySize     = 32 << 20
	PublicKeyEnvVar = "PICOD_AUTH_PUBLIC_KEY"
	maxFileMode     = 0777
)

type Config struct {
	Port      int
	Workspace string
}

type Server struct {
	engine       *gin.Engine
	config       Config
	authManager  *AuthManager
	startTime    time.Time
	workspaceDir string
}

type ExecuteRequest struct {
	Command    []string          `json:"command" binding:"required"`
	Timeout    string            `json:"timeout"`
	WorkingDir string            `json:"working_dir"`
	Env        map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string    `json:"stdout"`
	Stderr    string    `json:"stderr"`
	ExitCode  int       `json:"exit_code"`
	Duration  float64   `json:"duration"`
	StartTime time.Time `json:"start_time"`
	EndTime   time.Time `json:"end_time"`
}

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified time.Time `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode"`
}

type FileEntry struct {
	Name     string    `json:"name"`
	Size     int64     `json:"size"`
	Modified time.Time `json:"modified"`
	Mode     string    `json:"mode"`
	IsDir    bool      `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type AuthManager struct {
	publicKey *rsa.PublicKey
	mu        sync.RWMutex
}

func NewAuthManager() *AuthManager {
	return &AuthManager{}
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv(PublicKeyEnvVar)
	if keyData == "" {
		return fmt.Errorf("environment variable %s is not set", PublicKeyEnvVar)
	}

	block, _ := pem.Decode([]byte(keyData))
	if block == nil {
		return errors.New("failed to decode PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return err
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return errors.New("not an RSA public key")
	}

	am.mu.Lock()
	am.publicKey = rsaPub
	am.mu.Unlock()

	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "Missing authorization header",
				"code":   401,
				"detail": "JWT token is required",
			})
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid authorization header format",
				"code":   401,
				"detail": "Use Bearer <token>",
			})
			return
		}

		tokenString := parts[1]

		am.mu.RLock()
		pubKey := am.publicKey
		am.mu.RUnlock()

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return pubKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid token",
				"code":   401,
				"detail": err.Error(),
			})
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

func NewServer(config Config) (*Server, error) {
	s := &Server{
		config:    config,
		startTime: time.Now(),
	}

	if config.Workspace != "" {
		abs, err := filepath.Abs(config.Workspace)
		if err != nil {
			s.workspaceDir = config.Workspace
		} else {
			s.workspaceDir = abs
		}
	} else {
		wd, err := os.Getwd()
		if err != nil {
			return nil, err
		}
		s.workspaceDir = wd
	}

	s.authManager = NewAuthManager()
	if err := s.authManager.LoadPublicKeyFromEnv(); err != nil {
		return nil, err
	}

	gin.SetMode(gin.ReleaseMode)
	s.engine = gin.New()
	s.engine.Use(gin.Logger(), gin.Recovery())

	api := s.engine.Group("/api")
	api.Use(s.authManager.AuthMiddleware())
	{
		api.POST("/execute", s.ExecuteHandler)
		api.POST("/files", s.UploadFileHandler)
		api.GET("/files", s.ListFilesHandler)
		api.GET("/files/*path", s.DownloadFileHandler)
	}

	s.engine.GET("/health", s.HealthCheckHandler)

	return s, nil
}

func (s *Server) sanitizePath(p string) (string, error) {
	if s.workspaceDir == "" {
		return "", errors.New("workspace directory not initialized")
	}

	resolvedWorkspace := s.workspaceDir
	eval, err := filepath.EvalSymlinks(s.workspaceDir)
	if err == nil {
		resolvedWorkspace = eval
	}
	resolvedWorkspace = filepath.Clean(resolvedWorkspace)

	cleanPath := filepath.Clean(p)
	if strings.HasPrefix(cleanPath, string(os.PathSeparator)) {
		cleanPath = strings.TrimPrefix(cleanPath, string(os.PathSeparator))
	}

	fullPathCandidate := filepath.Join(resolvedWorkspace, cleanPath)

	rel, err := filepath.Rel(resolvedWorkspace, fullPathCandidate)
	if err != nil {
		return "", errors.New("access denied: path outside workspace")
	}

	if strings.HasPrefix(rel, "..") || rel == ".." {
		return "", errors.New("access denied: path escapes workspace")
	}

	return fullPathCandidate, nil
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command cannot be empty", "code": 400})
		return
	}

	timeout := 60 * time.Second
	if req.Timeout != "" {
		d, err := time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid timeout format", "code": 400})
			return
		}
		timeout = d
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	startTime := time.Now()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	if req.WorkingDir != "" {
		wd, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid working directory: " + err.Error(), "code": 400})
			return
		}
		cmd.Dir = wd
	} else {
		cmd.Dir = s.workspaceDir
	}

	if req.Env != nil {
		cmd.Env = os.Environ()
		for k, v := range req.Env {
			cmd.Env = append(cmd.Env, k+"="+v)
		}
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	cmd.Stdin = nil

	err := cmd.Run()

	endTime := time.Now()
	duration := endTime.Sub(startTime).Seconds()

	exitCode := 0
	if err != nil {
		if errors.Is(ctx.Err(), context.DeadlineExceeded) {
			exitCode = TimeoutExitCode
			stderr.WriteString(fmt.Sprintf("\ncommand timed out after %d seconds", int(timeout.Seconds())))
		} else if cmd.ProcessState != nil {
			exitCode = cmd.ProcessState.ExitCode()
		} else {
			exitCode = 1
			if stderr.Len() > 0 {
				stderr.WriteString("\n")
			}
			stderr.WriteString(err.Error())
		}
	}

	c.JSON(http.StatusOK, ExecuteResponse{
		Stdout:    stdout.String(),
		Stderr:    stderr.String(),
		ExitCode:  exitCode,
		Duration:  duration,
		StartTime: startTime,
		EndTime:   endTime,
	})
}

func parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return 0644
	}
	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil || mode > maxFileMode {
		return 0644
	}
	return os.FileMode(mode)
}

func (s *Server) UploadFileHandler(c *gin.Context) {
	contentType := c.ContentType()
	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
	} else {
		s.handleJSONBase64Upload(c)
	}
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required", "code": 400})
		return
	}

	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file is required", "code": 400})
		return
	}

	safePath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	mode := parseFileMode(c.PostForm("mode"))

	if err := os.MkdirAll(filepath.Dir(safePath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	src, err := file.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}
	defer src.Close()

	dst, err := os.OpenFile(safePath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	relPath, _ := filepath.Rel(s.workspaceDir, safePath)

	info, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     info.Size(),
		Mode:     info.Mode().String(),
		Modified: info.ModTime(),
	})
}

func (s *Server) handleJSONBase64Upload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid base64 content", "code": 400})
		return
	}

	safePath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	mode := parseFileMode(req.Mode)

	if err := os.MkdirAll(filepath.Dir(safePath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	if err := os.WriteFile(safePath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	relPath, _ := filepath.Rel(s.workspaceDir, safePath)

	info, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     info.Size(),
		Mode:     info.Mode().String(),
		Modified: info.ModTime(),
	})
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Missing 'path' query parameter", "code": 400})
		return
	}

	safePath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	entries, err := os.ReadDir(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "Directory not found", "code": 404})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	var files []FileEntry
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")
	path = strings.TrimPrefix(path, "/")

	safePath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	info, err := os.Stat(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "File not found", "code": 404})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error(), "code": 500})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Path is a directory, not a file", "code": 400})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(safePath)))

	contentType := mime.TypeByExtension(filepath.Ext(safePath))
	if contentType == "" {
		contentType = "application/octet-stream"
	}
	c.Header("Content-Type", contentType)

	c.File(safePath)
}

func (s *Server) HealthCheckHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "PicoD",
		"version": "0.0.1",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) Run() error {
	server := &http.Server{
		Addr:              fmt.Sprintf(":%d", s.config.Port),
		Handler:           s.engine,
		ReadHeaderTimeout: 10 * time.Second,
	}
	return server.ListenAndServe()
}

