package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func makeValkeyOptions() (valkey.ClientOption, error) {
	valkeyAddr := os.Getenv("VALKEY_ADDR")
	if valkeyAddr == "" {
		return valkey.ClientOption{}, errors.New("VALKEY_ADDR is required")
	}

	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if valkeyPassword == "" && strings.ToLower(passwordRequired) != "false" {
		return valkey.ClientOption{}, errors.New("VALKEY_PASSWORD is required when VALKEY_PASSWORD_REQUIRED is not false")
	}

	opts := valkey.ClientOption{
		InitAddress: strings.Split(valkeyAddr, ","),
		Password:    valkeyPassword,
	}

	if disableCache := os.Getenv("VALKEY_DISABLE_CACHE"); disableCache != "" {
		if v, err := strconv.ParseBool(disableCache); err == nil && v {
			opts.DisableCache = true
		}
	}

	if forceSingle := os.Getenv("VALKEY_FORCE_SINGLE"); forceSingle != "" {
		if v, err := strconv.ParseBool(forceSingle); err == nil && v {
			opts.ForceSingleClient = true
		}
	}

	return opts, nil
}

func newValkeyStore() (Store, error) {
	opts, err := makeValkeyOptions()
	if err != nil {
		return nil, err
	}

	cli, err := valkey.NewClient(opts)
	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (v *valkeyStore) sessionKey(sessionID string) string {
	return v.sessionPrefix + sessionID
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	result, err := v.cli.Do(ctx, v.cli.B().Ping().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := v.sessionKey(sessionID)
	result, err := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build()).AsBytes()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(result, &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is required")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := v.sessionKey(sandbox.SessionID)
	expiryScore := float64(sandbox.ExpiresAt.Unix())
	activityScore := float64(time.Now().Unix())

	commands := []valkey.Completed{
		v.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(valkey.Z{Score: expiryScore, Member: sandbox.SessionID}).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(valkey.Z{Score: activityScore, Member: sandbox.SessionID}).Build(),
	}

	_, err = v.cli.DoMulti(ctx, commands...).Result()
	return err
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	key := v.sessionKey(sandbox.SessionID)
	result, err := v.cli.Do(ctx, v.cli.B().Set().Key(key).Value(string(data)).Xx().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return errors.New("key not exists")
	}
	return nil
